import{_ as t,o,c as r,a3 as s}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"21. Casual Conversion","description":"","frontmatter":{"title":"21. Casual Conversion","eba":"Allied Health Professionals 2021-2026","topics":["employment","casual-conversion"]},"headers":[],"relativePath":"ebas/allied-health/employment/21-casual-conversion.md","filePath":"ebas/allied-health/employment/21-casual-conversion.md"}'),n={name:"ebas/allied-health/employment/21-casual-conversion.md"};function i(a,e,p,h,l,m){return o(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="_21-casual-conversion" tabindex="-1">21. Casual Conversion <a class="header-anchor" href="#_21-casual-conversion" aria-label="Permalink to &quot;21. Casual Conversion&quot;">​</a></h1><p><strong>21.1</strong> Employer offers</p><p><strong>(a)</strong> Subject to subclause 21.2, an Employer must make an offer to a casual Employee under this clause 21 if:</p><p><strong>(i)</strong> the casual Employee has been employed by the Employer for a period of 12 months beginning the day the employment started; and</p><p><strong>(ii)</strong> during at least the last six (6) months of that period, the Employee has worked a regular pattern of hours on an ongoing basis which, without significant adjustment, the Employee could continue to work as a full-time Employee or a part-time Employee (as the case may be).</p><p><strong>(b)</strong> The Employer&#39;s offer under subclause 21.1(a) must:</p><p><strong>(i)</strong> be in writing; and</p><p><strong>(ii)</strong> be an offer for the Employee to convert: A. for an Employee that has worked the equivalent of full-time hours during the period referred to in subclause 21.1(a)(ii) – to full-time employment; or B. for an Employee that has worked less than the equivalent of full-time hours during the period referred to in subclause 21.1(a)(ii) – to part-time employment that is consistent with the regular pattern of hours worked during that period;</p><p><strong>(iii)</strong> be given to the Employee within 21 days after the end of the 12-month period referred to in subclause 21.1(a)(i).</p><p><strong>21.2</strong> When Employer offers not required</p><p><strong>(a)</strong> Despite subclause 21.1, an Employer is not required to make an offer under subclause 21.1 to a casual Employee if:</p><p><strong>(i)</strong> there are reasonable grounds not to make that offer; and</p><p><strong>(ii)</strong> the reasonable grounds are based on facts that are known, or reasonably foreseeable, at the time of deciding not to make the offer.</p><p><strong>(b)</strong> Without limiting subclause 21.2(a)(i), reasonable grounds for deciding not to make an offer include the following:</p><p><strong>(i)</strong> the Employee&#39;s position will cease to exist in the period of 12 months after the time of deciding not to make the offer;</p><p><strong>(ii)</strong> the hours of work which the Employee is required to perform will be significantly reduced in that period;</p><p><strong>(iii)</strong> there will be a significant change in either or both of the following in that period: A. the days on which the Employee&#39;s hours of work are required to be performed; B. the times at which the Employee&#39;s hours of work are required to be performed; which cannot be accommodated within the days or times the Employee is available to work during that period;</p><p><strong>(iv)</strong> making the offer would not comply with a recruitment or selection process required by or under a law of the Commonwealth or a State or a Territory.</p><p><strong>(c)</strong> The Employer must give written notice to a casual Employee in accordance with subclause 21.2(d) if:</p><p><strong>(i)</strong> the Employer decides under subclause 21.2(a) not to make an offer to the Employee; or</p><p><strong>(ii)</strong> the Employee has been employed by the Employer for the 12-month period referred to in subclause 21.1(a)(i) but does not meet the requirement referred to in subclause 21.1(a)(ii).</p><p><strong>(d)</strong> The notice must:</p><p><strong>(i)</strong> advise the Employee that the Employer is not making an offer under subclause 21.1;</p><p><strong>(ii)</strong> include the details of the reasons for not making the offer (including any grounds on which the Employer has decided to not make the offer); and</p><p><strong>(iii)</strong> be given to the Employee within 21 days after the end of the 12-month period referred to in subclause 21.1(a)(i).</p><p><strong>21.3</strong> Employee response</p><p><strong>(a)</strong> The Employee must give the Employer a written response to the offer made under subclause 21.1(a) within 21 days after the offer is given to the Employee, stating whether the Employee accepts or declines the offer.</p><p><strong>(b)</strong> If the Employee fails to give the Employer a written response in accordance with subclause 21.3(a), the Employee is taken to have declined the offer.</p><p><strong>21.4</strong> Acceptances of offers</p><p><strong>(a)</strong> If the Employee accepts the offer, the Employer must, within 21 days after the day the acceptance is given to the Employer, give written notice to the Employee of the following:</p><p><strong>(i)</strong> whether the Employee is converting to full-time employment of part-time employment;</p><p><strong>(ii)</strong> the Employee&#39;s hours of work after the conversion takes effect; and</p><p><strong>(iii)</strong> the day the Employee&#39;s conversion to full-time or part-time employment takes effect.</p><p><strong>(b)</strong> However, the Employer must discuss with the Employee the matters the Employer intends to specify for the purposes of subclause 21.4(a)(i)-(iii) before giving the notice.</p><p><strong>(c)</strong> The day specified for the purposes of subclause 21.4(a)(iii) must be the first day of the Employee&#39;s first full pay period that starts after the day the notice is given, unless the Employee and Employer agree to another day.</p><p><strong>21.5</strong> Employee requests</p><p><strong>(a)</strong> A Casual Employee may make a request of an Employer under this subclause</p><p><strong>21.5</strong> if:</p><p><strong>(i)</strong> the Employee has been employed by the Employer for a period of at least 6 months beginning the day the employment started;</p><p><strong>(ii)</strong> the Employee has, in the period of 6 months ending the day the request is given, worked a regular pattern of hours on an ongoing basis which, without significant adjustment, the Employee could continue to work as a full-time Employee or part-time Employee (as the case may be); and</p><p><strong>(iii)</strong> all of the following apply: A. the Employee has not, at any time during the period referred to in subclause 21.5(a)(ii), refused an offer made to the Employee under subclause 21.1; B. the Employer has not, at any time during that period, given the Employee a notice in accordance with sub-clause 21.2(c)(i); C. the Employer has not, at any time during that period, given a response to the Employee under subclause 21.6 refusing a previous request made under this subclause 21.5; D. the request is not made during the period of 21 days after the period referred to in subclause 21.1(a)(i).</p><p><strong>(b)</strong> The request must:</p><p><strong>(i)</strong> be in writing;</p><p><strong>(ii)</strong> be a request for the Employee to convert:</p><p>A. for an Employee that has worked the equivalent of full-time hours during the period referred to in subclause 21.5(a)(ii) – to full-time employment; or B. for an Employee that has worked less than the equivalent of full-time hours during the period referred to in subclause 21.5(a)(ii) – to part-time employment that is consistent with the regular pattern of hours or shifts worked during that period; and</p><p><strong>(iii)</strong> be given to the Employer.</p><p><strong>21.6</strong> Employer must give a response The Employer must give the Employee a written response to the request made under subclause 21.5 within 21 days after the request is given to the Employer, stating whether the Employer grants or refuses the request.</p><p><strong>21.7</strong> Refusals of requests</p><p><strong>(a)</strong> The Employer must not refuse the request unless:</p><p><strong>(i)</strong> the Employer has consulted the Employee;</p><p><strong>(ii)</strong> there are reasonable grounds the refuse the request; and</p><p><strong>(iii)</strong> the reasonable grounds are based on facts that are known, or reasonably foreseeable, at the time of refusing the request.</p><p><strong>(b)</strong> Without limiting subclause 21.7(a)(ii), reasonable grounds for refusing a request include the following:</p><p><strong>(i)</strong> it would require a significant adjustment to the Employee’s hours of work in order for the Employee to be employed as a full-time Employee or part- time Employee;</p><p><strong>(ii)</strong> the Employee’s position will cease to exist in the period of 12 months after giving the request;</p><p><strong>(iii)</strong> the hours of work which the Employee is required to perform will be significantly reduced in the period of 12 months after giving the request;</p><p><strong>(iv)</strong> there will be a significant change in either or both of the following in the period of 12 months after giving the request: A. the days on which the Employee’s hours of work are required to be performed; B. the times at which the Employee’s hours of work are required to be performed; which cannot be accommodated within the days or times the Employee is available to work during that period;</p><p><strong>(v)</strong> granting the request would not comply with a recruitment or selection process required by or under a law of the Commonwealth or a State or a Territory.</p><p><strong>(c)</strong> If the Employer refuses the request, the written response under subclause 21.6 must include details of the reasons for the refusal.</p><p><strong>21.8</strong> Grants of requests</p><p><strong>(a)</strong> If the Employer grants the request made under subclause 21.5, the Employer must, within 21 days after the day the request is given to the Employer, give written notice to the Employee of the following:</p><p><strong>(i)</strong> whether the Employee is converting to full-time employment or part-time employment;</p><p><strong>(ii)</strong> the Employee&#39;s hours of work after the conversion takes effect; and</p><p><strong>(iii)</strong> the day the Employee&#39;s conversion to full-time or part-time employment takes effect.</p><p><strong>(b)</strong> However, the Employer must discuss with the Employee the matters the Employer intends to specify for the purposes of subclause 21.8(a)(i)-(iii) before giving the notice.</p><p><strong>(c)</strong> The day specified for the purposes of subclause 21.8(a)(iii) must be the first day of the Employee&#39;s first full pay period that starts after the day the notice is given, unless the Employee and Employer agree to another day.</p><p><strong>(d)</strong> To avoid doubt, the notice may be included in the written response under subclause 21.6</p><p><strong>21.9</strong> Effect of conversion</p><p><strong>(a)</strong> An Employee is taken, on and after the day specified in a notice for the purposes of subclauses 21.4(a)(iii) or 21.8(a)(iii) to be a full-time Employee or a part-time Employee of the Employer for the purposes of the following:</p><p><strong>(i)</strong> the Act and any other law of the Commonwealth;</p><p><strong>(ii)</strong> a law of a state or territory;</p><p><strong>(iii)</strong> the Agreement; and</p><p><strong>(iv)</strong> the Employee’s contract of employment.</p><p><strong>21.10</strong> Other rights and obligations</p><p><strong>(a)</strong> The Employer must not reduce or vary an Employee’s hours of work, or terminate an Employee’s employment, in order to avoid any right or obligation under this clause 21.</p><p><strong>(b)</strong> Nothing in this clause 21:</p><p><strong>(i)</strong> requires an Employee to convert to full-time employment or part-time employment;</p><p><strong>(ii)</strong> permits an Employer to require an Employee to convert to full-time employment or part-time employment;</p><p><strong>(iii)</strong> requires an Employer to increase the hours of work of an Employee who requests conversion to full-time employment or part-time employment under this clause 21.</p><p>Plain language terms: casual to permanent.</p>',80)])])}const f=t(n,[["render",i]]);export{g as __pageData,f as default};
